              className="absolute inset-0"
            >
              <Sparkles size={80} className="text-primary/30" />
            </motion.div>
          </motion.div>
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
