import { Heart, Calendar, MapPin, Clock } from "lucide-react";
import { motion, useMotionValue, useTransform, animate } from "framer-motion";
import { useEffect, useState } from "react";
import heroImage from "@assets/generated_images/Romantic_wedding_couple_hero_background_0afd25e7.png";
import { useQuery } from "@tanstack/react-query";
import type { CoupleInfo, Settings } from "@shared/schema";

export default function Hero() {
  const [isVisible, setIsVisible] = useState(false);
  const count = useMotionValue(0);
  const rounded = useTransform(count, Math.round);

  const { data: coupleInfo } = useQuery<CoupleInfo | null>({
    queryKey: ["/api/couple"],
  });

  const { data: settings } = useQuery<Settings | null>({
    queryKey: ["/api/settings"],
  });

  const [timeLeft, setTimeLeft] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    setIsVisible(true);

    const calculateTimeLeft = () => {
      const weddingDate = coupleInfo?.weddingDate 
        ? new Date(coupleInfo.weddingDate)
        : new Date('2025-06-15T00:00:00');
      const now = new Date();
      const difference = weddingDate.getTime() - now.getTime();

      if (difference > 0) {
        return {
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((difference / 1000 / 60) % 60),
          seconds: Math.floor((difference / 1000) % 60)
        };
      }
      return { days: 0, hours: 0, minutes: 0, seconds: 0 };
    };

    setTimeLeft(calculateTimeLeft());

    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, [coupleInfo?.weddingDate]);

  // Animate numbers
  useEffect(() => {
    Object.entries(timeLeft).forEach(([key, value]) => {
      const controls = animate(0, value, {
        duration: 1,
        onUpdate: (latest) => {
          // You would need separate motion values for each counter
          // This is simplified for demonstration
        }
      });
      return controls.stop;
    });
  }, [timeLeft]);

  const countdownItems = [
    { value: timeLeft.days, label: "Ngày", icon: Calendar },
    { value: timeLeft.hours, label: "Giờ", icon: Clock },
    { value: timeLeft.minutes, label: "Phút", icon: Clock },
    { value: timeLeft.seconds, label: "Giây", icon: Clock }
  ];

  const floatingHearts = [...Array(12)].map((_, i) => ({
    id: i,
    left: Math.random() * 100,
    delay: i * 1.5,
    duration: 18 + Math.random() * 10,
    size: 24 + Math.random() * 32
  }));

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.3,
        delayChildren: 0.2
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 50 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.8,
        ease: "easeOut"
      }
    }
  };

  const countdownVariants = {
    hidden: { opacity: 0, scale: 0.8 },
    visible: {
      opacity: 1,
      scale: 1,
      transition: {
        type: "spring",
        stiffness: 100,
        damping: 15
      }
    }
  };

  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden">
      {/* Background Image with Gradient Overlay */}
      <motion.div
        className="absolute inset-0 bg-cover bg-center bg-no-repeat"
        style={{ backgroundImage: `url(${heroImage})` }}
        initial={{ scale: 1.1 }}
        animate={{ scale: 1 }}
        transition={{ duration: 1.5, ease: "easeOut" }}
      >
        <motion.div
          className="absolute inset-0 bg-gradient-to-b from-primary/40 via-primary/20 to-background/90"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1.2 }}
        />
      </motion.div>

      {/* Animated Background Elements */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {/* Floating Hearts */}
        {floatingHearts.map((heart) => (
          <motion.div
            key={heart.id}
            className="absolute text-primary/20"
            style={{
              left: `${heart.left}%`,
              top: '110%',
              fontSize: `${heart.size}px`
            }}
            animate={{
              y: [-100, -window.innerHeight - 100],
              x: [0, Math.random() * 100 - 50],
              rotate: [0, 360],
              opacity: [0, 0.8, 0]
            }}
            transition={{
              duration: heart.duration,
              delay: heart.delay,
              repeat: Infinity,
              ease: "linear"
            }}
          >
            <Heart fill="currentColor" />
          </motion.div>
        ))}

        {/* Floating Particles */}
        {[...Array(20)].map((_, i) => (
          <motion.div
            key={`particle-${i}`}
            className="absolute w-1 h-1 bg-primary/30 rounded-full"
            style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              y: [0, -100],
              opacity: [0, 1, 0],
              scale: [0, 1, 0]
            }}
            transition={{
              duration: 4 + Math.random() * 4,
              delay: Math.random() * 5,
              repeat: Infinity,
              ease: "easeInOut"
            }}
          />
