              {coupleInfo ? `${coupleInfo.brideName} & ${coupleInfo.groomName}` : "Sarah & Michael"}
            </span>
            {/* Decorative underline */}
            <motion.div
              className="absolute -bottom-4 left-1/2 transform -translate-x-1/2 w-32 h-1 bg-primary rounded-full"
