                transition={{
                  duration: 3,
                  repeat: Infinity,
                  ease: "easeInOut"
                }}
              >
                <Heart size={16} className="text-primary" fill="currentColor" />
                <span>Sarah & Michael - 15.06.2025</span>
                <Heart size={16} className="text-primary" fill="currentColor" />
              </motion.div>
            </motion.div>
          </CardContent>
        </Card>

        {/* Decorative Elements */}
        <motion.div
          className="flex justify-center gap-2 mt-8"
          variants={containerVariants}
        >
          {[...Array(3)].map((_, i) => (
            <motion.div
              key={i}
              className="w-2 h-2 bg-primary/30 rounded-full"
              animate={{
                scale: [1, 1.5, 1],
                opacity: [0.5, 1, 0.5],
