import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Save, Settings as SettingsIcon, Music, MapPin, Palette, Bell, Shield, Eye, Upload } from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import type { Settings } from "@shared/schema";
import { insertSettingsSchema } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { motion } from "framer-motion";
import { useState, useEffect } from "react";
import { Badge } from "@/components/ui/badge";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

export default function AdminSettings() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState("general");

  const { data: settings, isLoading } = useQuery<Settings | null>({
    queryKey: ["/api/settings"],
  });

  const form = useForm({
    resolver: zodResolver(insertSettingsSchema),
    defaultValues: {
      venueName: "",
      venueAddress: "",
      venueMapLink: "",
      venuePhone: "",
      venueEmail: "",
      eventStartTime: undefined,
      eventEndTime: undefined,
      backgroundMusicUrl: "",
      backgroundMusicType: "youtube",
    },
  });

  // Reset form when settings are loaded
  useEffect(() => {
    if (settings) {
      form.reset({
        venueName: settings.venueName || "",
        venueAddress: settings.venueAddress || "",
        venueMapLink: settings.venueMapLink || "",
        venuePhone: settings.venuePhone || "",
        venueEmail: settings.venueEmail || "",
        eventStartTime: settings.eventStartTime ? new Date(settings.eventStartTime).toISOString().slice(0, 16) as any : undefined,
        eventEndTime: settings.eventEndTime ? new Date(settings.eventEndTime).toISOString().slice(0, 16) as any : undefined,
        backgroundMusicUrl: settings.backgroundMusicUrl || "",
        backgroundMusicType: settings.backgroundMusicType || "youtube",
      });
    }
  }, [settings, form]);

  const updateMutation = useMutation({
    mutationFn: async (data: typeof insertSettingsSchema._type) => {
      return await apiRequest("POST", "/api/settings", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/settings"] });
      toast({ 
        title: "✅ Cài đặt đã được lưu",
        description: "Thay đổi của bạn đã được cập nhật thành công"
      });
    },
    onError: (error: Error) => {
      if (isUnauthorizedError(error)) {
        window.location.href = "/api/login";
        return;
      }
      toast({
        title: "❌ Lỗi",
        description: "Không thể lưu cài đặt",
        variant: "destructive",
      });
    },
  });

  const onSubmit = form.handleSubmit((data) => {
    updateMutation.mutate(data);
  });

  const tabs = [
    { id: "general", label: "🌐 Tổng Quan", icon: SettingsIcon },
    { id: "appearance", label: "🎨 Giao Diện", icon: Palette },
    { id: "features", label: "⚙️ Tính Năng", icon: Bell },
    { id: "security", label: "🔒 Bảo Mật", icon: Shield },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: "easeOut"
      }
    }
  };

  if (isLoading) {
    return (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        <div className="mb-8">
          <h2 className="text-3xl font-serif mb-2 text-foreground">⚙️ Cài Đặt Website</h2>
          <p className="text-muted-foreground">Cấu hình trang web đám cưới của bạn</p>
        </div>
        <Card className="animate-pulse">
          <CardHeader>
            <div className="h-6 bg-muted rounded w-1/4" />
          </CardHeader>
          <CardContent className="space-y-4">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="h-10 bg-muted rounded" />
            ))}
          </CardContent>
        </Card>
      </motion.div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      {/* Header */}
      <motion.div 
        className="mb-8"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <motion.div variants={itemVariants}>
          <h2 className="text-3xl font-serif mb-2 text-foreground">⚙️ Cài Đặt Website</h2>
          <p className="text-muted-foreground text-lg">Tùy chỉnh và cấu hình trang web đám cưới của bạn</p>
        </motion.div>
      </motion.div>

      <div className="grid lg:grid-cols-4 gap-6">
        {/* Sidebar Navigation */}
        <motion.div variants={itemVariants}>
          <Card className="sticky top-6">
            <CardContent className="p-4">
              <nav className="space-y-2">
                {tabs.map((tab) => {
                  const IconComponent = tab.icon;
                  return (
                    <button
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id)}
                      className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg text-left transition-all duration-200 ${
                        activeTab === tab.id
                          ? "bg-primary text-primary-foreground shadow-lg"
                          : "text-foreground hover:bg-muted"
                      }`}
                    >
                      <IconComponent size={18} />
                      <span className="font-medium">{tab.label}</span>
                    </button>
                  );
                })}
              </nav>
            </CardContent>
          </Card>
        </motion.div>

        {/* Main Content */}
        <motion.div 
          className="lg:col-span-3"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <Form {...form}>
            <form onSubmit={onSubmit}>
            <AnimatedTabContent activeTab={activeTab}>
              {/* General Settings */}
              {activeTab === "general" && (
                <div className="space-y-6">
                  <Card>
                    <CardHeader className="bg-gradient-to-r from-primary/5 to-primary/10 border-b">
                      <CardTitle className="flex items-center gap-2">
                        <SettingsIcon className="text-primary" size={20} />
                        Thông Tin Cơ Bản
                      </CardTitle>
                    </CardHeader>
                  </Card>

                  <Card>
                    <CardHeader className="bg-gradient-to-r from-blue-500/5 to-blue-500/10 border-b">
                      <CardTitle className="flex items-center gap-2">
                        <MapPin className="text-blue-500" size={20} />
                        Thông Tin Địa Điểm
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-6">
                      <FormField
                        control={form.control}
                        name="venueName"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">Tên Địa Điểm *</FormLabel>
                            <FormControl>
                              <Input
                                placeholder="Khách sạn Grand Ballroom"
                                className="h-12 text-lg"
                                data-testid="input-venue-name"
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="venueAddress"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">Địa Chỉ Địa Điểm *</FormLabel>
                            <FormControl>
                              <Input
                                placeholder="123 Đường Cưới, Quận 1, Thành phố Hồ Chí Minh"
                                className="h-12 text-lg"
                                data-testid="input-venue-address"
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={form.control}
                        name="venueMapLink"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">Link Google Maps</FormLabel>
                            <FormControl>
                              <Input
                                type="url"
                                placeholder="https://www.google.com/maps/search/?api=1&query=..."
                                className="h-12"
                                data-testid="input-venue-map-link"
                                {...field}
                              />
                            </FormControl>
                            <p className="text-xs text-muted-foreground">
                              Link Google Maps để khách mời có thể chỉ đường dễ dàng
                            </p>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <div className="grid md:grid-cols-2 gap-4">
                        <FormField
                          control={form.control}
                          name="venuePhone"
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel className="text-sm font-medium">📞 Số Điện Thoại Liên Hệ</FormLabel>
                              <FormControl>
                                <Input
                                  type="tel"
                                  placeholder="(84) 123-456-789"
                                  className="h-12"
                                  data-testid="input-venue-phone"
                                  {...field}
                                />
                              </FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />

                        <FormField
                          control={form.control}
                          name="venueEmail"
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel className="text-sm font-medium">📧 Email Liên Hệ</FormLabel>
                              <FormControl>
                                <Input
                                  type="email"
                                  placeholder="contact@venue.com"
                                  className="h-12"
                                  data-testid="input-venue-email"
                                  {...field}
                                />
                              </FormControl>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>

                      <div className="grid md:grid-cols-2 gap-4">
                        <FormField
                          control={form.control}
                          name="eventStartTime"
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel className="text-sm font-medium">⏰ Thời Gian Bắt Đầu</FormLabel>
                              <FormControl>
                                <Input
                                  type="datetime-local"
                                  className="h-12"
                                  data-testid="input-event-start-time"
                                  {...field}
                                />
                              </FormControl>
                              <p className="text-xs text-muted-foreground">
                                Thời gian bắt đầu sự kiện
                              </p>
                              <FormMessage />
                            </FormItem>
                          )}
                        />

                        <FormField
                          control={form.control}
                          name="eventEndTime"
                          render={({ field }) => (
                            <FormItem>
                              <FormLabel className="text-sm font-medium">⏱️ Thời Gian Kết Thúc</FormLabel>
                              <FormControl>
                                <Input
                                  type="datetime-local"
                                  className="h-12"
                                  data-testid="input-event-end-time"
                                  {...field}
                                />
                              </FormControl>
                              <p className="text-xs text-muted-foreground">
                                Thời gian dự kiến kết thúc sự kiện
                              </p>
                              <FormMessage />
                            </FormItem>
                          )}
                        />
                      </div>
                    </CardContent>
                  </Card>
                </div>
              )}

              {/* Appearance Settings */}
              {activeTab === "appearance" && (
                <div className="space-y-6">
                  <Card>
                    <CardHeader className="bg-gradient-to-r from-purple-500/5 to-purple-500/10 border-b">
                      <CardTitle className="flex items-center gap-2">
                        <Palette className="text-purple-500" size={20} />
                        Màu Sắc & Giao Diện
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-6">
                      <div className="p-4 bg-muted/50 rounded-lg">
                        <p className="text-sm text-muted-foreground">
                          Các tùy chỉnh giao diện sẽ được bổ sung trong phiên bản tiếp theo
                        </p>
                      </div>
                    </CardContent>
                  </Card>
                </div>
              )}

              {/* Features Settings */}
              {activeTab === "features" && (
                <div className="space-y-6">
                  <Card>
                    <CardHeader className="bg-gradient-to-r from-orange-500/5 to-orange-500/10 border-b">
                      <CardTitle className="flex items-center gap-2">
                        <Music className="text-orange-500" size={20} />
                        Cài Đặt Âm Thanh
                      </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-6">
                      <FormField
                        control={form.control}
                        name="backgroundMusicType"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">Loại Nhạc Nền</FormLabel>
                            <Select onValueChange={field.onChange} defaultValue={field.value}>
                              <FormControl>
                                <SelectTrigger className="h-12" data-testid="select-music-type">
                                  <SelectValue placeholder="Chọn loại nhạc" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
