                </div>
              )}
            </AnimatedTabContent>

            {/* Save Button */}
            <motion.div 
              className="flex justify-end gap-4 mt-6 p-6 bg-card border rounded-lg sticky bottom-6 shadow-lg"
              variants={itemVariants}
            >
