import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent } from "@/components/ui/card";
import { 
  Image as ImageIcon, 
  Plus, 
  Trash2, 
  Pencil, 
  Eye, 
  Download, 
  Search, 
  Filter,
  Upload,
  X,
  CloudUpload
} from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import type { Photo, InsertPhoto } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { motion, AnimatePresence } from "framer-motion";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { uploadImageToCloudinary } from "@/lib/imageUpload";

export default function AdminGallery() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingPhoto, setEditingPhoto] = useState<Photo | null>(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { data: photos = [], isLoading } = useQuery<Photo[]>({
    queryKey: ["/api/photos"],
  });

  // Filter photos based on search and category
  const filteredPhotos = photos.filter(photo => {
    const matchesSearch = photo.caption?.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         photo.category?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === "all" || photo.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const categories = Array.from(new Set(photos.map(photo => photo.category).filter(Boolean)));

  const createMutation = useMutation({
    mutationFn: async (data: InsertPhoto) => {
      return await apiRequest("POST", "/api/photos", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/photos"] });
      toast({ 
        title: "✅ Thêm ảnh thành công",
        description: "Ảnh đã được thêm vào thư viện"
      });
      setIsDialogOpen(false);
      setUploading(false);
      setUploadProgress(0);
    },
    onError: (error: Error) => {
      if (isUnauthorizedError(error)) {
        window.location.href = "/api/login";
        return;
      }
      toast({
        title: "❌ Lỗi",
        description: "Không thể thêm ảnh",
        variant: "destructive",
      });
      setUploading(false);
      setUploadProgress(0);
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<InsertPhoto> }) => {
      return await apiRequest("PATCH", `/api/photos/${id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/photos"] });
      toast({ 
        title: "✅ Cập nhật ảnh thành công",
        description: "Thông tin ảnh đã được cập nhật"
      });
      setIsDialogOpen(false);
      setEditingPhoto(null);
    },
    onError: (error: Error) => {
      if (isUnauthorizedError(error)) {
        window.location.href = "/api/login";
        return;
      }
      toast({
        title: "❌ Lỗi",
        description: "Không thể cập nhật ảnh",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return await apiRequest("DELETE", `/api/photos/${id}`, undefined);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/photos"] });
      toast({ 
        title: "🗑️ Xóa ảnh thành công",
        description: "Ảnh đã được xóa khỏi thư viện"
      });
    },
    onError: (error: Error) => {
      if (isUnauthorizedError(error)) {
        window.location.href = "/api/login";
        return;
      }
      toast({
        title: "❌ Lỗi",
        description: "Không thể xóa ảnh",
        variant: "destructive",
      });
    },
  });

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      toast({
        title: "❌ Lỗi",
        description: "Vui lòng chọn file hình ảnh (JPEG, PNG, WebP)",
        variant: "destructive",
      });
      return;
    }

    // Validate file size (10MB)
    if (file.size > 10 * 1024 * 1024) {
      toast({
        title: "❌ Lỗi",
        description: "Kích thước file không được vượt quá 10MB",
        variant: "destructive",
      });
      return;
    }

    setUploading(true);
    setUploadProgress(0);

    try {
      const imageUrl = await uploadImageToCloudinary(file, (progress) => {
        setUploadProgress(progress);
      });

      // Auto-fill the URL field with the uploaded image URL
      const urlInput = document.getElementById('url') as HTMLInputElement;
      if (urlInput) {
        urlInput.value = imageUrl;
      }

      toast({
        title: "✅ Tải lên thành công!",
        description: "Ảnh đã được tải lên Cloudinary",
      });
    } catch (error) {
      toast({
        title: "❌ Lỗi",
        description: "Không thể tải lên ảnh",
        variant: "destructive",
      });
    } finally {
      setUploading(false);
      // Reset file input
      if (event.target) {
        event.target.value = '';
      }
    }
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const data: InsertPhoto = {
      url: formData.get("url") as string,
      caption: formData.get("caption") as string,
      category: formData.get("category") as string || "gallery",
      order: parseInt(formData.get("order") as string) || 0,
    };

    if (editingPhoto) {
      updateMutation.mutate({ id: editingPhoto.id, data });
    } else {
      createMutation.mutate(data);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: "easeOut"
      }
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, scale: 0.8 },
    visible: {
      opacity: 1,
      scale: 1,
      transition: {
        type: "spring",
        stiffness: 100,
        damping: 15
      }
    },
    hover: {
      y: -8,
      scale: 1.02,
      transition: {
        type: "spring",
        stiffness: 400,
        damping: 25
      }
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      {/* Hidden file input */}
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileSelect}
        accept="image/*"
        className="hidden"
      />

      {/* Header */}
      <motion.div 
        className="mb-8"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <motion.div className="flex justify-between items-center mb-6" variants={itemVariants}>
          <div>
            <h2 className="text-3xl font-serif mb-2 text-foreground">📸 Thư Viện Ảnh</h2>
            <p className="text-muted-foreground">Quản lý ảnh đám cưới của bạn</p>
          </div>
          <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
            <DialogTrigger asChild>
              <Button 
                onClick={() => setEditingPhoto(null)}
                className="rounded-xl shadow-lg hover:shadow-xl transition-all duration-300"
              >
                <Plus size={18} className="mr-2" />
                Thêm Ảnh
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  {editingPhoto ? "✏️ Chỉnh Sửa Ảnh" : "🖼️ Thêm Ảnh Mới"}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="url" className="text-sm font-medium">URL Hình Ảnh *</Label>
                  <div className="flex gap-2">
                    <Input
                      id="url"
                      name="url"
                      type="url"
                      required
                      placeholder="https://example.com/photo.jpg"
                      defaultValue={editingPhoto?.url}
                      className="flex-1"
                    />
                    <Button 
                      type="button" 
                      variant="outline" 
                      size="icon" 
                      onClick={triggerFileInput}
                      disabled={uploading}
                    >
                      {uploading ? (
                        <motion.div
                          animate={{ rotate: 360 }}
                          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                        >
                          ⏳
                        </motion.div>
                      ) : (
                        <CloudUpload size={16} />
                      )}
                    </Button>
                  </div>

                  {/* Upload Progress */}
                  {uploading && (
                    <div className="space-y-2">
                      <Progress value={uploadProgress} className="h-2" />
                      <p className="text-xs text-muted-foreground text-center">
                        Đang tải lên... {Math.round(uploadProgress)}%
                      </p>
                    </div>
                  )}

                  {/* Upload Instructions */}
                  <p className="text-xs text-muted-foreground">
                    Nhập URL hoặc tải lên từ thiết bị (JPEG, PNG, WebP, tối đa 10MB)
                  </p>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="caption" className="text-sm font-medium">Chú Thích</Label>
                  <Textarea
                    id="caption"
                    name="caption"
                    rows={3}
                    placeholder="Mô tả bức ảnh này..."
                    defaultValue={editingPhoto?.caption || ""}
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="category" className="text-sm font-medium">Danh Mục</Label>
                    <Input
                      id="category"
                      name="category"
                      placeholder="engagement, wedding, etc."
                      defaultValue={editingPhoto?.category || "gallery"}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="order" className="text-sm font-medium">Thứ Tự</Label>
                    <Input
                      id="order"
                      name="order"
                      type="number"
                      min="0"
                      defaultValue={editingPhoto?.order || 0}
                    />
                  </div>
                </div>

                <div className="flex justify-end gap-2 pt-4">
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => {
                      setIsDialogOpen(false);
                      setUploading(false);
                      setUploadProgress(0);
                    }}
                    className="rounded-lg"
                  >
                    Hủy
                  </Button>
                  <Button 
                    type="submit" 
                    className="rounded-lg shadow-lg"
                    disabled={createMutation.isPending || updateMutation.isPending || uploading}
                  >
                    {editingPhoto ? "💾 Cập Nhật" : "📤 Thêm"} Ảnh
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>
        </motion.div>

        {/* Search and Filter */}
        <motion.div className="flex flex-col sm:flex-row gap-4 mb-6" variants={itemVariants}>
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={18} />
            <Input
              placeholder="🔍 Tìm kiếm ảnh theo chú thích hoặc danh mục..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 rounded-xl"
            />
          </div>
          <div className="flex gap-2">
            <Select value={selectedCategory} onValueChange={setSelectedCategory}>
              <SelectTrigger className="w-40 rounded-xl">
                <Filter size={16} className="mr-2" />
                <SelectValue placeholder="Tất cả danh mục" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">🎯 Tất cả</SelectItem>
                {categories.map(category => (
                  <SelectItem key={category} value={category}>
                    {category}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </motion.div>

        {/* Stats */}
        <motion.div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6" variants={itemVariants}>
          <Card className="bg-primary/5 border-primary/20 rounded-2xl">
            <CardContent className="p-4 text-center">
              <p className="text-2xl font-bold text-primary">{photos.length}</p>
              <p className="text-sm text-muted-foreground">Tổng số ảnh</p>
            </CardContent>
          </Card>
          <Card className="bg-blue-500/5 border-blue-500/20 rounded-2xl">
            <CardContent className="p-4 text-center">
              <p className="text-2xl font-bold text-blue-500">{categories.length}</p>
              <p className="text-sm text-muted-foreground">Danh mục</p>
            </CardContent>
          </Card>
          <Card className="bg-green-500/5 border-green-500/20 rounded-2xl">
            <CardContent className="p-4 text-center">
              <p className="text-2xl font-bold text-green-500">
                {photos.filter(p => p.category === 'wedding').length}
              </p>
              <p className="text-sm text-muted-foreground">Ảnh cưới</p>
            </CardContent>
          </Card>
          <Card className="bg-purple-500/5 border-purple-500/20 rounded-2xl">
            <CardContent className="p-4 text-center">
              <p className="text-2xl font-bold text-purple-500">
                {photos.filter(p => p.category === 'engagement').length}
              </p>
              <p className="text-sm text-muted-foreground">Ảnh đính hôn</p>
            </CardContent>
          </Card>
        </motion.div>
      </motion.div>

      {/* Gallery Grid */}
      {isLoading ? (
        <motion.div
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          {[...Array(8)].map((_, i) => (
            <motion.div key={i} variants={itemVariants}>
              <Card className="animate-pulse overflow-hidden rounded-2xl">
                <div className="aspect-square bg-muted" />
                <CardContent className="p-4 space-y-2">
                  <div className="h-4 bg-muted rounded w-3/4" />
                  <div className="h-3 bg-muted rounded w-1/2" />
                </CardContent>
              </Card>
            </motion.div>
          ))}
        </motion.div>
      ) : (
        <motion.div
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <AnimatePresence>
            {filteredPhotos.length === 0 ? (
              <motion.div
                className="col-span-full"
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.6 }}
              >
                <Card className="border-dashed rounded-2xl">
                  <CardContent className="py-16 text-center text-muted-foreground">
                    <ImageIcon size={64} className="mx-auto mb-4 opacity-50" />
                    <p className="text-lg mb-2">Không tìm thấy ảnh nào</p>
                    <p>Thử thay đổi bộ lọc hoặc thêm ảnh mới</p>
                    <Button 
                      className="mt-4 rounded-xl"
                      onClick={() => setIsDialogOpen(true)}
                    >
                      <Plus size={18} className="mr-2" />
                      Thêm Ảnh Đầu Tiên
                    </Button>
                  </CardContent>
                </Card>
              </motion.div>
            ) : (
              filteredPhotos.map((photo, index) => (
                <motion.div
                  key={photo.id}
                  variants={cardVariants}
                  initial="hidden"
                  animate="visible"
                  whileHover="hover"
                  exit="hidden"
                  transition={{ delay: index * 0.1 }}
                >
                  <Card className="group overflow-hidden shadow-lg hover:shadow-xl transition-all duration-300 border-0 bg-card/50 backdrop-blur-sm rounded-2xl">
                    <div className="relative aspect-square overflow-hidden">
                      <motion.img
                        src={photo.url}
                        alt={photo.caption || "Ảnh đám cưới"}
                        className="w-full h-full object-cover cursor-pointer"
                        whileHover={{ scale: 1.1 }}
                        transition={{ duration: 0.3 }}
                        onClick={() => setPreviewImage(photo.url)}
                      />

                      {/* Overlay Actions */}
                      <motion.div
                        className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center gap-2"
                        initial={{ opacity: 0 }}
                        whileHover={{ opacity: 1 }}
                      >
                        <Button
                          variant="secondary"
                          size="sm"
                          className="rounded-full shadow-lg bg-white/20 hover:bg-white/30 backdrop-blur-sm"
                          onClick={() => setPreviewImage(photo.url)}
                        >
                          <Eye size={16} />
                        </Button>
                        <Button
                          variant="secondary"
                          size="sm"
                          className="rounded-full shadow-lg bg-white/20 hover:bg-white/30 backdrop-blur-sm"
                          onClick={() => {
                            setEditingPhoto(photo);
                            setIsDialogOpen(true);
                          }}
                        >
                          <Pencil size={16} />
                        </Button>
                        <Button
                          variant="secondary"
                          size="sm"
                          className="rounded-full shadow-lg bg-destructive/20 hover:bg-destructive/30 backdrop-blur-sm"
                          onClick={() => {
                            if (confirm("Bạn có chắc muốn xóa ảnh này?")) {
                              deleteMutation.mutate(photo.id);
                            }
                          }}
                        >
                          <Trash2 size={16} className="text-destructive" />
                        </Button>
                      </motion.div>

                      {/* Category Badge */}
                      {photo.category && (
                        <Badge 
                          variant="secondary" 
                          className="absolute top-3 left-3 bg-black/70 text-white border-0 backdrop-blur-sm rounded-full px-3 py-1"
                        >
                          {photo.category}
                        </Badge>
                      )}
                    </div>

                    <CardContent className="p-4">
                      {photo.caption && (
                        <p className="text-sm text-foreground line-clamp-2 mb-2 font-medium">
                          {photo.caption}
                        </p>
                      )}
                      <div className="flex justify-between items-center text-xs text-muted-foreground">
                        <span>Thứ tự: {photo.order}</span>
                        <span>
                          {new Date(photo.createdAt!).toLocaleDateString('vi-VN')}
                        </span>
                      </div>
                    </CardContent>
                  </Card>
                </motion.div>
              ))
            )}
          </AnimatePresence>
        </motion.div>
      )}

      {/* Image Preview Dialog */}
      <Dialog open={!!previewImage} onOpenChange={() => setPreviewImage(null)}>
        <DialogContent className="max-w-4xl p-0 bg-transparent border-0 shadow-none">
          <div className="relative">
            {previewImage && (
              <img
                src={previewImage}
                alt="Preview"
                className="w-full h-auto rounded-2xl shadow-2xl"
              />
            )}
            <Button
              variant="secondary"
              size="icon"
              className="absolute top-4 right-4 rounded-full bg-black/50 hover:bg-black/70 text-white backdrop-blur-sm"
              onClick={() => setPreviewImage(null)}
            >
              <X size={20} />
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </motion.div>
  );
}

server/db.ts.content:
import * as dotenv from 'dotenv';
dotenv.config();

import { Pool } from 'pg';
import { drizzle } from 'drizzle-orm/node-postgres';
import * as schema from "@shared/schema";

console.log('DATABASE_URL loaded:', !!process.env.DATABASE_URL);

if (!process.env.DATABASE_URL) {
  throw new Error(
    "DATABASE_URL must be set. Did you forget to provision a database?",
  );
}

// Sử dụng pg Pool thay vì Neon serverless
export const pool = new Pool({ 
  connectionString: process.env.DATABASE_URL,
  ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: false } : false,
  // Thêm các config để ổn định kết nối
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 10000,
});

export const db = drizzle(pool, { schema });

// Test connection
async function testConnection() {
  try {
    const client = await pool.connect();
    console.log('✅ Connected to Neon database successfully!');

    const result = await client.query('SELECT NOW()');
    console.log('📅 Database time:', result.rows[0].now);

    client.release();
  } catch (error) {
    console.error('❌ Failed to connect to Neon:', error);
  }
}

testConnection();

client/src/components/Gallery.tsx.content:
import { useState, useEffect } from "react";
import { X, ChevronLeft, ChevronRight, Heart, Download, Share2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { motion, AnimatePresence } from "framer-motion";
import type { Photo } from "@shared/schema";

export default function Gallery() {
  const [selectedPhoto, setSelectedPhoto] = useState<number | null>(null);
  const [direction, setDirection] = useState(0);

  const { data: photos = [], isLoading, isError, error } = useQuery<Photo[]>({
    queryKey: ["/api/photos"],
  });

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (selectedPhoto !== null) {
        if (e.key === "Escape") closeLightbox();
        if (e.key === "ArrowRight") {
          setDirection(1);
          nextPhoto();
        }
        if (e.key === "ArrowLeft") {
          setDirection(-1);
          prevPhoto();
        }
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [selectedPhoto]);

  const openLightbox = (index: number) => {
    setSelectedPhoto(index);
    setDirection(0);
  };

  const closeLightbox = () => setSelectedPhoto(null);

  const nextPhoto = () => {
    setDirection(1);
    setSelectedPhoto((prev) => (prev !== null ? (prev + 1) % photos.length : 0));
  };

  const prevPhoto = () => {
    setDirection(-1);
    setSelectedPhoto((prev) =>
      prev !== null ? (prev === 0 ? photos.length - 1 : prev - 1) : 0
    );
  };

  const sharePhoto = async (photo: Photo) => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: "Ảnh cưới Sarah & Michael",
          text: photo.caption || "Chia sẻ khoảnh khắc đặc biệt",
          url: photo.url,
        });
      } catch (err) {
        console.log("Sharing cancelled");
      }
    } else {
      // Fallback: copy to clipboard
      navigator.clipboard.writeText(photo.url);
      // You can add a toast notification here
    }
  };

  const downloadPhoto = async (url: string, filename: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = downloadUrl;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(downloadUrl);
    } catch (err) {
      console.error("Download failed:", err);
    }
  };

  // Animation variants
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { 
      opacity: 0, 
      scale: 0.8,
      y: 30
    },
    visible: {
      opacity: 1,
      scale: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: "easeOut"
      }
    }
  };

  const slideVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 1000 : -1000,
      opacity: 0,
      scale: 0.8
    }),
    center: {
      x: 0,
      opacity: 1,
      scale: 1,
      transition: {
        duration: 0.5,
        ease: "easeOut"
      }
    },
    exit: (direction: number) => ({
      x: direction < 0 ? 1000 : -1000,
      opacity: 0,
      scale: 0.8,
      transition: {
        duration: 0.3
      }
    })
  };

  return (
    <section id="gallery" className="py-20 md:py-32 px-4 bg-card overflow-hidden">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2
            className="font-serif text-4xl md:text-5xl mb-4 text-foreground"
            data-testid="heading-gallery"
          >
            Album Ảnh
          </h2>
          <motion.div
            className="w-24 h-1 bg-primary mx-auto mb-4"
            initial={{ width: 0 }}
            whileInView={{ width: "6rem" }}
            transition={{ duration: 0.8, delay: 0.3 }}
            viewport={{ once: true }}
          />
          <motion.p
            className="text-muted-foreground text-lg"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            transition={{ duration: 0.6, delay: 0.5 }}
            viewport={{ once: true }}
          >
            Những kỷ niệm chúng tôi đã tạo ra cùng nhau
          </motion.p>
        </motion.div>

        {/* Photo Grid - Masonry Layout */}
        {isLoading ? (
          <motion.div
            className="columns-1 sm:columns-2 lg:columns-3 xl:columns-4 gap-4 space-y-4"
            variants={containerVariants}
            initial="hidden"
            animate="visible"
          >
            {[...Array(8)].map((_, i) => (
              <motion.div
                key={i}
                variants={itemVariants}
                className="rounded-2xl overflow-hidden bg-gradient-to-br from-muted to-muted/50 animate-pulse break-inside-avoid mb-4"
                style={{ height: `${200 + (i % 3) * 80}px` }}
                whileHover={{ scale: 1.02 }}
                transition={{ duration: 0.3 }}
              />
            ))}
          </motion.div>
        ) : isError ? (
          <motion.div
            className="text-center py-16"
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.6 }}
          >
            <motion.div
              animate={{ 
                scale: [1, 1.1, 1],
                rotate: [0, -5, 5, 0]
              }}
              transition={{ duration: 2, repeat: Infinity }}
            >
              <Heart className="mx-auto mb-4 text-destructive" size={64} />
            </motion.div>
            <p className="text-destructive text-lg mb-2">Không thể tải ảnh</p>
            <p className="text-muted-foreground">
              {error instanceof Error ? error.message : "Vui lòng thử lại sau"}
            </p>
          </motion.div>
        ) : photos.length === 0 ? (
          <motion.div
            className="text-center py-16"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.6 }}
          >
            <motion.div
              animate={{ 
                scale: [1, 1.2, 1],
              }}
              transition={{ duration: 3, repeat: Infinity }}
            >
              <Heart className="mx-auto mb-4 text-muted-foreground" size={64} />
            </motion.div>
            <p className="text-muted-foreground text-lg">Chưa có ảnh. Hãy quay lại sau!</p>
          </motion.div>
        ) : (
          <motion.div
            className="columns-1 sm:columns-2 lg:columns-3 xl:columns-4 gap-4"
            variants={containerVariants}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-50px" }}
          >
            {photos.map((photo, index) => (
              <motion.div
                key={photo.id}
                variants={itemVariants}
                className="group relative overflow-hidden rounded-2xl cursor-pointer shadow-lg bg-background break-inside-avoid mb-4"
                whileHover={{ 
                  scale: 1.02,
                  y: -4,
                  boxShadow: "0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)"
                }}
                whileTap={{ scale: 0.98 }}
                transition={{ type: "spring", stiffness: 400, damping: 25 }}
                onClick={() => openLightbox(index)}
                data-testid={`photo-${index}`}
              >
                <motion.img
                  src={photo.url}
                  alt={photo.caption || "Ảnh cưới"}
                  className="w-full h-auto object-cover"
                  whileHover={{ scale: 1.05 }}
                  transition={{ duration: 0.5 }}
                />

                {/* Overlay */}
                <motion.div
                  className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-500 flex flex-col justify-end p-4"
                  initial={{ opacity: 0 }}
                  whileHover={{ opacity: 1 }}
                >
                  {photo.caption && (
                    <motion.p
                      className="text-white text-sm font-medium mb-2"
                      initial={{ y: 20, opacity: 0 }}
                      whileHover={{ y: 0, opacity: 1 }}
                      transition={{ delay: 0.1 }}
                    >
                      {photo.caption}
                    </motion.p>
                  )}
                  <motion.div
                    className="flex gap-2"
                    initial={{ y: 20, opacity: 0 }}
                    whileHover={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.2 }}
                  >
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        sharePhoto(photo);
                      }}
                      className="p-2 bg-white/20 rounded-full backdrop-blur-sm hover:bg-white/30 transition-colors"
                    >
                      <Share2 size={16} className="text-white" />
                    </button>
                  </motion.div>
                </motion.div>
              </motion.div>
            ))}
          </motion.div>
        )}

        {/* Lightbox Modal */}
        <AnimatePresence mode="wait" custom={direction}>
          {selectedPhoto !== null && photos.length > 0 && (
            <motion.div
              className="fixed inset-0 bg-black/95 z-50 flex items-center justify-center p-4"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={closeLightbox}
            >
              {/* Close Button */}
              <motion.button
                onClick={closeLightbox}
                className="absolute top-6 right-6 text-white hover:text-primary transition-colors p-3 rounded-full bg-white/10 backdrop-blur-sm z-10"
                data-testid="button-close-lightbox"
                whileHover={{ scale: 1.1, rotate: 90 }}
                whileTap={{ scale: 0.9 }}
              >
                <X size={24} />
              </motion.button>

              {/* Navigation Buttons */}
              <motion.button
                onClick={(e) => {
                  e.stopPropagation();
                  prevPhoto();
                }}
                className="absolute left-6 text-white hover:text-primary transition-colors p-3 rounded-full bg-white/10 backdrop-blur-sm z-10"
                data-testid="button-prev-photo"
                whileHover={{ scale: 1.1, x: -2 }}
                whileTap={{ scale: 0.9 }}
              >
                <ChevronLeft size={32} />
              </motion.button>

              <motion.button
                onClick={(e) => {
                  e.stopPropagation();
                  nextPhoto();
                }}
                className="absolute right-6 text-white hover:text-primary transition-colors p-3 rounded-full bg-white/10 backdrop-blur-sm z-10"
                data-testid="button-next-photo"
                whileHover={{ scale: 1.1, x: 2 }}
                whileTap={{ scale: 0.9 }}
              >
                <ChevronRight size={32} />
              </motion.button>

              {/* Action Buttons */}
              <motion.button
                onClick={(e) => {
                  e.stopPropagation();
                  downloadPhoto(photos[selectedPhoto].url, `photo-${selectedPhoto + 1}.jpg`);
                }}
                className="absolute top-6 left-6 text-white hover:text-primary transition-colors p-3 rounded-full bg-white/10 backdrop-blur-sm z-10"
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
              >
                <Download size={24} />
              </motion.button>

              {/* Photo Display */}
              <motion.div
                className="max-w-5xl max-h-[90vh] flex flex-col items-center"
                onClick={(e) => e.stopPropagation()}
                custom={direction}
                variants={slideVariants}
                initial="enter"
                animate="center"
                exit="exit"
                key={selectedPhoto}
              >
                <motion.img
                  src={photos[selectedPhoto].url}
                  alt={photos[selectedPhoto].caption || "Ảnh cưới"}
                  className="max-w-full max-h-[80vh] object-contain rounded-lg shadow-2xl"
                  data-testid="img-lightbox"
                />
                {photos[selectedPhoto].caption && (
                  <motion.p
                    className="text-white text-center mt-4 text-lg bg-white/10 backdrop-blur-sm rounded-full px-6 py-3"
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                  >
                    {photos[selectedPhoto].caption}
                  </motion.p>
                )}
              </motion.div>

              {/* Photo Counter */}
              <motion.div
                className="absolute bottom-6 left-1/2 transform -translate-x-1/2 text-white/80 bg-white/10 backdrop-blur-sm rounded-full px-4 py-2"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4 }}
              >
                {selectedPhoto + 1} / {photos.length}
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </section>
  );
}

